            parts.append(c)
    return "".join(parts)

starter:
def shift_letters(s, k):
    # your code here
    pass

solution:
def shift_letters(s, k):
    parts = []
    for c in s:
        if 'a' <= c <= 'z':
            idx = (ord(c) - ord('a') + k) % 26
            parts.append(chr(ord('a') + idx))
        else:
            parts.append(c)
    return "".join(parts)

